/**
 * cat_maps.js
 * Route to Ítaca — Catalonia Local & Comarca Map Painter
 *
 * Pure visualization layer. All winners are pre-computed in Q:
 *
 *   Cities/towns  →  Q["local_" + cityId + "_wp"]
 *                    e.g. Q["local_barcelona_wp"] = "bcomuns"
 *                         Q["local_la-seu-durgell_wp"] = "erc"
 *
 *   Comarca race scores (used to shade comarques):
 *     Red Belt   →  Q.cs_local_redbelt, Q.erc_local_redbelt  (0–100)
 *     Interior   →  Q.erc_local_interior, Q.cup_local_interior,
 *                   Q.ciu_local_interior, Q.fnc_local_interior (0–100)
 *                   (ciu_local_interior acts as the holdout threshold)
 *
 * Exposed globals:
 *   initCatLocalMap(containerId, Q)
 */
